-- Уроки 1-8 курса промптинга
INSERT INTO t_p80207328_code_school_online.lessons
  (course_id, position, title, duration, intro, steps, software) VALUES

('ai-prompting', 1, 'Что такое промпт и как работает ИИ', '12:00',
'Промпт — это текстовый запрос, который ты даёшь нейросети. От того, насколько точно он сформулирован, зависит 90% результата. В этом уроке поймём, как «думает» ИИ и почему одни запросы работают, а другие — нет. Теория короткая, дальше сразу практика.',
'[
  {"title": "Шаг 1. Открой ChatGPT", "text": "Зайди на chat.openai.com (или chatgpt.com). Нужен VPN, если сервис недоступен в твоём регионе — подробнее в блоке «Что нужно для урока». Зарегистрируйся через почту или Google."},
  {"title": "Шаг 2. Задай простой вопрос", "text": "Напиши в поле ввода: «Расскажи, что такое нейросеть, простыми словами». Отправь и прочитай ответ. Это твой первый промпт."},
  {"title": "Шаг 3. Пойми главное правило", "text": "ИИ не «знает» правильный ответ — он предсказывает наиболее вероятное продолжение текста. Поэтому чем яснее и подробнее запрос, тем точнее ответ. Расплывчатый промпт = расплывчатый ответ."},
  {"title": "Шаг 4. Сравни два запроса", "text": "Напиши: «Напиши текст». Посмотри результат. Затем: «Напиши поздравительный текст коллеге на день рождения, дружеский тон, 3 предложения». Сравни — второй ответ намного полезнее."},
  {"title": "Шаг 5. Сделай вывод", "text": "Запомни формулу хорошего промпта: ЧТО нужно + ДЛЯ КОГО/ЗАЧЕМ + В КАКОМ ВИДЕ. Дальше в курсе разберём каждую часть детально."}
]',
'[
  {"name": "ChatGPT", "desc": "Самая популярная нейросеть от OpenAI. На ней будем практиковаться.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN, если сервис не открывается в твоём регионе. Включи VPN, зайди на chatgpt.com и зарегистрируйся через email или Google-аккаунт."},
  {"name": "VPN", "desc": "Нужен для доступа к ChatGPT и другим ИИ-сервисам из России.", "url": "https://ru.wikipedia.org/wiki/VPN", "install": "Установи любой надёжный VPN-сервис (расширение для браузера или приложение). Включай его перед заходом на ИИ-сервисы."}
]'),

('ai-prompting', 2, 'Формула идеального промпта', '15:00',
'Есть проверенная структура, которая превращает средний запрос в отличный. Разберём 5 элементов: роль, задача, контекст, формат, ограничения. Научившись собирать промпт по этой формуле, ты будешь получать качественные ответы стабильно, а не случайно.',
'[
  {"title": "Шаг 1. Задача (что сделать)", "text": "Начни промпт с чёткого глагола действия: «Напиши», «Составь», «Проанализируй», «Переведи». Например: «Составь план поста для соцсетей»."},
  {"title": "Шаг 2. Контекст (детали ситуации)", "text": "Добавь детали: о чём, для кого, зачем. «Составь план поста для соцсетей о запуске онлайн-курса по фотографии, аудитория — новички 25-40 лет»."},
  {"title": "Шаг 3. Формат (в каком виде)", "text": "Укажи, как оформить ответ: «в виде списка из 5 пунктов», «таблицей», «абзацем до 500 знаков». ИИ выдаст ровно ту структуру, что ты просишь."},
  {"title": "Шаг 4. Ограничения (рамки)", "text": "Задай границы: «без сложных терминов», «дружелюбный тон», «не более 3 эмодзи». Это убирает лишнее и делает ответ точным."},
  {"title": "Шаг 5. Собери всё вместе", "text": "Скопируй в ChatGPT полный промпт: «Составь план поста для соцсетей о запуске курса по фотографии для новичков 25-40 лет. Формат: список из 5 пунктов. Тон дружелюбный, без сложных терминов». Оцени, насколько ответ лучше простого «напиши пост»."}
]',
'[
  {"name": "ChatGPT", "desc": "Практикуемся в составлении промптов по формуле.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 3, 'Роли: заставь ИИ стать экспертом', '14:00',
'Один из самых мощных приёмов — назначить нейросети роль. «Ты опытный маркетолог», «Ты редактор издательства» — и качество ответа резко вырастает, потому что ИИ начинает отвечать с точки зрения специалиста. Освоим этот приём на практике.',
'[
  {"title": "Шаг 1. Обычный запрос без роли", "text": "Напиши в ChatGPT: «Проверь мой текст на ошибки: Мы предлогаем лучшие услуги на рынке». Запомни ответ."},
  {"title": "Шаг 2. Добавь роль", "text": "Теперь напиши: «Ты профессиональный корректор с 20-летним опытом. Проверь мой текст на ошибки и объясни каждую: Мы предлогаем лучшие услуги на рынке». Ответ станет глубже и профессиональнее."},
  {"title": "Шаг 3. Экспериментируй с ролями", "text": "Попробуй разные роли для одной задачи: «Ты SMM-специалист», «Ты копирайтер Apple», «Ты школьный учитель». Одна и та же просьба даст разные по стилю ответы."},
  {"title": "Шаг 4. Усиль роль деталями", "text": "Чем конкретнее роль, тем лучше: не просто «ты дизайнер», а «ты UX-дизайнер, который делал приложения для банков и знает, как упрощать интерфейсы»."},
  {"title": "Шаг 5. Закрепи навык", "text": "Составь промпт с ролью для своей реальной задачи. Например: «Ты диетолог. Составь план питания на день для офисного работника, который хочет похудеть». Оцени результат."}
]',
'[
  {"name": "ChatGPT", "desc": "Пробуем назначать роли нейросети.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 4, 'Контекст: чем больше деталей, тем лучше', '16:00',
'ИИ не читает мысли. Если не дать контекст — он додумает за тебя, и часто неверно. В этом уроке научимся насыщать промпт нужными деталями: кто ты, для кого результат, какая цель, какие есть ограничения. Это превращает общие ответы в точные и применимые.',
'[
  {"title": "Шаг 1. Пойми проблему без контекста", "text": "Напиши: «Напиши письмо клиенту». ИИ выдаст шаблон ни о чём, потому что не знает деталей."},
  {"title": "Шаг 2. Добавь кто ты", "text": "«Я владелец небольшой кофейни. Напиши письмо клиенту». Уже лучше — появляется специфика."},
  {"title": "Шаг 3. Добавь ситуацию", "text": "«Я владелец кофейни. Постоянный клиент оставил негативный отзыв о медленном обслуживании. Напиши ему письмо-извинение с предложением бесплатного кофе»."},
  {"title": "Шаг 4. Добавь тон и длину", "text": "Допиши: «Тон — искренний и тёплый, без канцелярита, до 4 предложений». Теперь ответ полностью готов к использованию."},
  {"title": "Шаг 5. Правило 5W", "text": "Запомни: давай ответы на Who (кто), What (что), Why (зачем), Whom (для кого), When (когда). Чем больше из этого в промпте — тем точнее результат."}
]',
'[
  {"name": "ChatGPT", "desc": "Учимся давать контекст.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 5, 'Примеры в промпте (few-shot)', '15:00',
'Хочешь, чтобы ИИ отвечал в определённом стиле или формате? Покажи ему пример. Техника «few-shot» — это когда ты даёшь 1-3 образца, и нейросеть подхватывает нужный шаблон. Это один из самых надёжных способов получить предсказуемый результат.',
'[
  {"title": "Шаг 1. Пойми идею", "text": "Иногда проще показать, чем объяснить. Вместо долгого описания формата ты даёшь готовый пример — и ИИ копирует его логику."},
  {"title": "Шаг 2. Промпт с одним примером", "text": "Напиши: «Придумай слоганы для кофейни в таком стиле. Пример: „Тот самый вкус утра“. Дай ещё 5 в том же духе»."},
  {"title": "Шаг 3. Промпт с несколькими примерами", "text": "Дай 2-3 образца: «Преврати черту продукта в выгоду. Пример 1: Батарея 5000 мАч → Работает 2 дня без розетки. Пример 2: Вес 1 кг → Носи весь день и не устанешь. Теперь сделай для: Экран 120 Гц»."},
  {"title": "Шаг 4. Задай формат через пример", "text": "Покажи структуру: «Оформи ответ так: Заголовок — Описание (1 строка). Пример: Скорость — приложение открывается за секунду. Сделай 4 таких пункта про наше приложение»."},
  {"title": "Шаг 5. Практика", "text": "Возьми свою задачу и добавь 1-2 примера желаемого ответа. Убедись, что ИИ точно повторяет стиль и формат образца."}
]',
'[
  {"name": "ChatGPT", "desc": "Осваиваем технику примеров.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 6, 'Формат ответа: списки, таблицы, JSON', '14:00',
'ИИ может выдать ответ в любом виде — нужно только попросить. Списки, таблицы, пошаговые инструкции, даже данные для программ (JSON). Умение управлять форматом экономит время: получаешь сразу готовый к использованию результат, а не сплошной текст.',
'[
  {"title": "Шаг 1. Проси список", "text": "Напиши: «Дай 7 идей для видео на YouTube про кулинарию. Формат — нумерованный список». Получишь аккуратный перечень."},
  {"title": "Шаг 2. Проси таблицу", "text": "«Сравни 3 тарифа интернета: Базовый, Оптимальный, Премиум по скорости, цене и трафику. Формат — таблица». ИИ построит таблицу с колонками."},
  {"title": "Шаг 3. Проси пошаговую инструкцию", "text": "«Опиши, как заварить фильтр-кофе. Формат — пронумерованные шаги с временем на каждый»."},
  {"title": "Шаг 4. Проси структуру для программ", "text": "«Дай 3 товара с полями name, price, category в формате JSON». Это пригодится, если данные нужны для сайта или таблицы."},
  {"title": "Шаг 5. Комбинируй", "text": "Попроси: «Ответ дай в виде таблицы, а под ней — краткий вывод одним абзацем». ИИ выполнит оба требования."}
]',
'[
  {"name": "ChatGPT", "desc": "Управляем форматом ответов.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 7, 'Цепочка рассуждений (chain of thought)', '17:00',
'Для сложных задач есть приём: попросить ИИ рассуждать пошагово, а не выдавать ответ сразу. Фраза «думай шаг за шагом» заметно повышает точность в логике, математике и анализе. Разберём, когда и как это применять.',
'[
  {"title": "Шаг 1. Задача без рассуждения", "text": "Напиши логическую задачу: «В корзине 3 яблока, ты забрал 2. Сколько яблок у тебя?». Иногда ИИ ошибается, отвечая быстро."},
  {"title": "Шаг 2. Добавь волшебную фразу", "text": "Допиши: «Думай шаг за шагом, прежде чем дать ответ». ИИ распишет логику и придёт к верному результату (у тебя 2 яблока — те, что забрал)."},
  {"title": "Шаг 3. Применяй для анализа", "text": "«Проанализируй, стоит ли открывать кофейню в спальном районе. Рассуждай пошагово: спрос, конкуренты, затраты, риски, вывод»."},
  {"title": "Шаг 4. Проси показать ход мыслей", "text": "Для проверки решений: «Реши задачу и покажи все промежуточные вычисления». Так ты видишь, где логика могла сломаться."},
  {"title": "Шаг 5. Когда использовать", "text": "Применяй пошаговое рассуждение для математики, логики, планирования, сложного выбора. Для простых задач это не нужно — только замедлит."}
]',
'[
  {"name": "ChatGPT", "desc": "Учим ИИ рассуждать пошагово.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]'),

('ai-prompting', 8, 'Итерации: как дорабатывать ответ', '15:00',
'Первый ответ ИИ — черновик, а не финал. Настоящая сила промптинга в диалоге: уточняй, критикуй, проси переделать. В этом уроке научимся вести беседу с нейросетью так, чтобы за несколько шагов дойти до идеального результата.',
'[
  {"title": "Шаг 1. Получи первый вариант", "text": "Попроси: «Напиши короткое описание для товара — беспроводные наушники». Прими ответ как черновик."},
  {"title": "Шаг 2. Уточни, что не так", "text": "Ответь в том же чате: «Слишком сухо. Добавь эмоций и подчеркни свободу без проводов». ИИ помнит контекст и переделает."},
  {"title": "Шаг 3. Проси варианты", "text": "«Дай ещё 3 версии этого описания: одну короткую, одну с юмором, одну премиальную». Выбери лучшую."},
  {"title": "Шаг 4. Попроси ИИ покритиковать себя", "text": "«Оцени свой текст по шкале 1-10 и предложи, как его улучшить». ИИ найдёт слабые места сам."},
  {"title": "Шаг 5. Финальная шлифовка", "text": "«Возьми лучший вариант и сократи до 2 предложений, сохранив главную выгоду». Так за 4-5 сообщений получаешь готовый результат."}
]',
'[
  {"name": "ChatGPT", "desc": "Ведём диалог и дорабатываем ответы.", "url": "https://chatgpt.com", "install": "⚠️ Потребуется VPN. Включи VPN и открой chatgpt.com."}
]');